#include <stdio.h>
#include <stdlib.h>
#include <omp.h>
#include "common.h"

#define BLOCK_SIZE 16

void lud_diagonal(float *m, int matrix_dim, int offset) {
    int i, j;
    float shadow[BLOCK_SIZE][BLOCK_SIZE];

    int array_offset = offset * matrix_dim + offset;
    #pragma omp parallel for
    for (i = 0; i < BLOCK_SIZE; i++) {
        shadow[i][0] = m[array_offset];
        array_offset += matrix_dim;
    }

    #pragma omp barrier

    #pragma omp parallel for
    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        #pragma omp parallel for
        for (j = 0; j < BLOCK_SIZE; j++) {
            if (j > i) {
                shadow[j][i] -= shadow[j][0] * shadow[0][i];
            }
        }
        #pragma omp barrier
        #pragma omp parallel for
        for (j = 0; j < BLOCK_SIZE; j++) {
            if (j > i) {
                shadow[i + 1][j] -= shadow[i + 1][0] * shadow[0][j];
            }
        }
        #pragma omp barrier
    }

    array_offset = (offset + 1) * matrix_dim + offset;
    #pragma omp parallel for
    for (i = 1; i < BLOCK_SIZE; i++) {
        m[array_offset] = shadow[i][0];
        array_offset += matrix_dim;
    }
}

void lud_perimeter(float *m, int matrix_dim, int offset) {
    int i, j;
    float dia[BLOCK_SIZE][BLOCK_SIZE];
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];

    int array_offset;
    int idx;

    #pragma omp parallel for
    for (i = 0; i < BLOCK_SIZE; i++) {
        idx = i;
        array_offset = offset * matrix_dim + offset;
        for (j = 0; j < BLOCK_SIZE / 2; j++) {
            dia[j][idx] = m[array_offset + idx];
            array_offset += matrix_dim;
        }

        array_offset = offset * matrix_dim + offset;
        for (j = 0; j < BLOCK_SIZE; j++) {
            peri_row[j][idx] = m[array_offset + (1 + offset / BLOCK_SIZE) * BLOCK_SIZE + idx];
            array_offset += matrix_dim;
        }
    }

    #pragma omp barrier

    #pragma omp parallel for
    for (i = BLOCK_SIZE; i < 2 * BLOCK_SIZE; i++) {
        idx = i - BLOCK_SIZE;
        array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
        for (j = BLOCK_SIZE / 2; j < BLOCK_SIZE; j++) {
            dia[j][idx] = m[array_offset + idx];
            array_offset += matrix_dim;
        }

        array_offset = (offset + (1 + offset / BLOCK_SIZE) * BLOCK_SIZE) * matrix_dim + offset;
        for (j = 0; j < BLOCK_SIZE; j++) {
            peri_col[j][idx] = m[array_offset + idx];
            array_offset += matrix_dim;
        }
    }

    #pragma omp barrier

    #pragma omp parallel for
    for (i = 0; i < BLOCK_SIZE; i++) {
        idx = i;
        for (j = 1; j < BLOCK_SIZE; j++) {
            for (int k = 0; k < j; k++) {
                peri_row[j][idx] -= dia[j][k] * peri_row[k][idx];
            }
        }
    }

    #pragma omp barrier

    #pragma omp parallel for
    for (i = BLOCK_SIZE; i < 2 * BLOCK_SIZE; i++) {
        idx = i - BLOCK_SIZE;
        for (j = 0; j < BLOCK_SIZE; j++) {
            for (int k = 0; k < j; k++) {
                peri_col[idx][j] -= peri_col[idx][k] * dia[k][j];
            }
            peri_col[idx][j] /= dia[j][j];
        }
    }

    #pragma omp barrier

    #pragma omp parallel for
    for (i = 0; i < BLOCK_SIZE; i++) {
        idx = i;
        array_offset = (offset + 1) * matrix_dim + offset;
        for (j = 1; j < BLOCK_SIZE; j++) {
            m[array_offset + (1 + offset / BLOCK_SIZE) * BLOCK_SIZE + idx] = peri_row[j][idx];
            array_offset += matrix_dim;
        }
    }

    #pragma omp barrier

    #pragma omp parallel for
    for (i = BLOCK_SIZE; i < 2 * BLOCK_SIZE; i++) {
        idx = i - BLOCK_SIZE;
        array_offset = (offset + (1 + offset / BLOCK_SIZE) * BLOCK_SIZE) * matrix_dim + offset;
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[array_offset + idx] = peri_col[j][idx];
            array_offset += matrix_dim;
        }
    }
}

void lud_internal(float *m, int matrix_dim, int offset) {
    int i, j, k;
    float sum;
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];

    int global_row_id = offset + (1 + offset / BLOCK_SIZE) * BLOCK_SIZE;
    int global_col_id = offset + (1 + offset / BLOCK_SIZE) * BLOCK_SIZE;

    #pragma omp parallel for
    for (i = 0; i < BLOCK_SIZE; i++) {
        peri_row[0][i] = m[(offset + 0) * matrix_dim + global_col_id + i];
    }

    #pragma omp barrier

    #pragma omp parallel for
    for (i = 0; i < BLOCK_SIZE; i++) {
        peri_col[i][0] = m[(global_row_id + i) * matrix_dim + offset + 0];
    }

    #pragma omp barrier

    #pragma omp parallel for
    for (i = 0; i < BLOCK_SIZE; i++) {
        sum = 0;
        for (j = 0; j < BLOCK_SIZE; j++) {
            sum += peri_col[i][j] * peri_row[j][0];
        }
        m[(global_row_id + i) * matrix_dim + global_col_id + 0] -= sum;
    }
}

void lud_omp(float *m, int matrix_dim) {
    int i;

    #pragma omp parallel
    {
        #pragma omp single
        for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
            lud_diagonal(m, matrix_dim, i);
            lud_perimeter(m, matrix_dim, i);
            lud_internal(m, matrix_dim, i);
        }
        lud_diagonal(m, matrix_dim, i);
    }
}
